                    .start("InitiateMultipartUploadResult", AwsNamespaces.S3)
                    .elem("Bucket", bucket)
                    .elem("Key", key)
                    .elem("UploadId", upload.getUploadId())
                    .end("InitiateMultipartUploadResult")
                    .build();
            return Response.ok(xml).build();
