                    .elem("ChecksumSHA1", part.getChecksum().getChecksumSHA1())
                    .elem("ChecksumSHA256", part.getChecksum().getChecksumSHA256())
                    .elem("PartNumber", part.getPartNumber())
                    .elem("Size", part.getSize())
