    private Map<String, String> extractUserMetadata(HttpHeaders httpHeaders) {
        Map<String, String> metadata = new LinkedHashMap<>();
        for (Map.Entry<String, List<String>> entry : httpHeaders.getRequestHeaders().entrySet()) {
