    private boolean eTagMatches(String headerValue, String eTag) {
        if ("*".equals(headerValue.trim())) {
            return true;
        }
        for (String candidate : headerValue.split(",")) {
            if (candidate.trim().equals(eTag)) {
                return true;
            }
        }
        return false;
    }

